export interface Product {
  id: string;
  name: string;
  category: Category;
  description: string;
  price: number;
  originalPrice?: number;
  rating: number;
  reviewCount: number;
  image: string;
  stock: number;
  isNew?: boolean;
}

export type Category = 'All' | 'Laptops' | 'Audio' | 'Wearables' | 'Smart Home';

export interface CartItem extends Product {
  quantity: number;
}

export interface CheckoutFormData {
  email: string;
  firstName: string;
  lastName: string;
  address: string;
  city: string;
  zipCode: string;
}

export enum View {
  HOME = 'home',
  CHECKOUT = 'checkout',
  CONFIRMATION = 'confirmation'
}

import { GoogleGenAI, Type } from "@google/genai";
import { Product } from '../types';
import { MOCK_PRODUCTS } from '../constants';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getSmartSearch = async (query: string): Promise<string[]> => {
  if (!process.env.API_KEY) return MOCK_PRODUCTS.map(p => p.id);

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given this product list: ${JSON.stringify(MOCK_PRODUCTS.map(p => ({id: p.id, name: p.name, desc: p.description})))}. 
      The user search query is: "${query}". 
      Return only a JSON array of product IDs that best match this query.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Gemini Search Error:", error);
    return MOCK_PRODUCTS.map(p => p.id);
  }
};

