import React from 'react';
import { X, Minus, Plus, Trash2, ShoppingBag } from 'lucide-react';
import { CartItem } from '../types';
import { VAT_RATE } from '../constants';

interface CartProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onUpdateQuantity: (id: string, delta: number) => void;
  onRemoveItem: (id: string) => void;
  onCheckout: () => void;
}

const Cart: React.FC<CartProps> = ({ 
  isOpen, 
  onClose, 
  items, 
  onUpdateQuantity, 
  onRemoveItem,
  onCheckout 
}) => {
  const subtotal = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const vat = subtotal * VAT_RATE;
  const total = subtotal + vat;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] overflow-hidden">
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={onClose} />

      <div className="absolute inset-y-0 right-0 max-w-full flex">
        <div className="w-screen max-w-md transform transition-all duration-500 translate-x-0">
          <div className="h-full flex flex-col bg-white shadow-2xl">
            {/* Header */}
            <div className="flex items-center justify-between px-6 py-6 border-b border-slate-100">
              <div className="flex items-center gap-3">
                <ShoppingBag className="text-[#137fec]" />
                <h2 className="text-xl font-extrabold text-slate-900">Your Cart</h2>
                <span className="bg-slate-100 px-2.5 py-0.5 rounded-full text-xs font-bold text-slate-500">{items.length}</span>
              </div>
              <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>

            {/* Items */}
            <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide">
              {items.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
                  <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center text-slate-300">
                    <ShoppingBag size={40} />
                  </div>
                  <h3 className="text-lg font-bold text-slate-900">Your cart is empty</h3>
                  <p className="text-slate-500 max-w-[200px]">Looks like you haven't added anything yet.</p>
                  <button 
                    onClick={onClose}
                    className="mt-4 px-8 py-3 bg-[#137fec] text-white font-bold rounded-xl shadow-lg shadow-blue-500/20"
                  >
                    Start Shopping
                  </button>
                </div>
              ) : (
                items.map((item) => (
                  <div key={item.id} className="flex gap-4">
                    <div className="w-24 h-24 bg-slate-50 rounded-xl overflow-hidden shrink-0">
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 flex flex-col">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-slate-900 leading-tight pr-4">{item.name}</h4>
                        <button 
                          onClick={() => onRemoveItem(item.id)}
                          className="text-slate-300 hover:text-rose-500 transition-colors"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                      <p className="text-xs text-slate-400 mt-1">{item.category}</p>

                      <div className="mt-auto flex items-center justify-between">
                        <div className="flex items-center gap-3 bg-slate-100 rounded-lg p-1">
                          <button 
                            onClick={() => onUpdateQuantity(item.id, -1)}
                            className="w-7 h-7 flex items-center justify-center bg-white rounded shadow-sm hover:text-[#137fec] disabled:opacity-50"
                            disabled={item.quantity <= 1}
                          >
                            <Minus size={14} />
                          </button>
                          <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.id, 1)}
                            className="w-7 h-7 flex items-center justify-center bg-white rounded shadow-sm hover:text-[#137fec]"
                          >
                            <Plus size={14} />
                          </button>
                        </div>
                        <span className="font-bold text-slate-900">${item.price * item.quantity}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            {/* Footer */}
            {items.length > 0 && (
              <div className="border-t border-slate-100 p-6 space-y-4 bg-slate-50/50">
                <div className="space-y-2 text-sm">
                  <div className="flex justify-between text-slate-500">
                    <span>Subtotal</span>
                    <span className="font-semibold text-slate-900">${subtotal.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-slate-500">
                    <span>VAT (7.5%)</span>
                    <span className="font-semibold text-slate-900">${vat.toFixed(2)}</span>
                  </div>
                  <div className="pt-2 flex justify-between text-lg font-black text-slate-900">
                    <span>Total</span>
                    <span>${total.toFixed(2)}</span>
                  </div>
                </div>

                <button 
                  onClick={onCheckout}
                  className="w-full py-4 bg-[#137fec] text-white font-bold rounded-xl shadow-xl shadow-blue-500/30 hover:bg-blue-600 transition-all flex items-center justify-center gap-3 group"
                >
                  Proceed to Checkout
                  <Plus className="group-hover:rotate-90 transition-transform" size={20} />
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Cart;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import Cart from './components/Cart';
import { Product, CartItem, Category, View, CheckoutFormData } from './types';
import { MOCK_PRODUCTS, VAT_RATE } from './constants';
import { ChevronRight, CheckCircle2, ShieldCheck, Truck, CreditCard, ArrowLeft, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<View>(View.HOME);
  const [activeCategory, setActiveCategory] = useState<Category>('All');
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [lastRef, setLastRef] = useState('');

  // Persist cart
  useEffect(() => {
    const saved = localStorage.getItem('techstore_cart');
    if (saved) setCartItems(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('techstore_cart', JSON.stringify(cartItems));
  }, [cartItems]);

  const cartCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  const filteredProducts = useMemo(() => {
    if (activeCategory === 'All') return MOCK_PRODUCTS;
    return MOCK_PRODUCTS.filter(p => p.category === activeCategory);
  }, [activeCategory]);

  const handleAddToCart = (product: Product) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id 
          ? { ...item, quantity: item.quantity + 1 } 
          : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleUpdateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const handleRemoveItem = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const calculateTotals = () => {
    const subtotal = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const vat = subtotal * VAT_RATE;
    const total = subtotal + vat;
    return { subtotal, vat, total };
  };

  const handleCheckout = () => {
    setIsCartOpen(false);
    setView(View.CHECKOUT);
    window.scrollTo(0, 0);
  };

  const handleProcessPayment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    // Simulate Paystack payment
    setTimeout(() => {
      setIsProcessing(false);
      setLastRef(`TS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`);
      setView(View.CONFIRMATION);
      setCartItems([]);
      window.scrollTo(0, 0);
    }, 2500);
  };

  return (
    <Layout 
      cartCount={cartCount} 
      onOpenCart={() => setIsCartOpen(true)} 
      onNavigateHome={() => setView(View.HOME)}
      activeCategory={activeCategory}
      setActiveCategory={setActiveCategory}
    >
      {view === View.HOME && (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
          <Hero />

          <div className="space-y-8">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-100 pb-8">
              <div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Trending Now</h2>
                <p className="text-slate-500 mt-1">Discover our most popular products this week.</p>
              </div>
              <div className="flex flex-wrap items-center gap-2">
                {['All', 'Laptops', 'Audio', 'Wearables', 'Smart Home'].map((cat) => (
                  <button
                    key={cat}
                    onClick={() => setActiveCategory(cat as Category)}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all ${
                      activeCategory === cat 
                      ? 'bg-[#137fec] text-white shadow-lg shadow-blue-500/25' 
                      : 'bg-white text-slate-600 hover:bg-slate-100 border border-slate-100'
                    }`}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {filteredProducts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={handleAddToCart} 
                />
              ))}
            </div>

            <div className="flex justify-center pt-16">
              <button className="px-10 py-4 bg-white border-2 border-slate-100 text-slate-900 font-bold rounded-xl hover:border-[#137fec] hover:text-[#137fec] transition-all flex items-center gap-2 group">
                Load More Products
                <ChevronRight size={18} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </div>
          </div>
        </div>
      )}

      {view === View.CHECKOUT && (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
          <button 
            onClick={() => setView(View.HOME)}
            className="flex items-center gap-2 text-slate-500 hover:text-[#137fec] font-bold text-sm mb-10 transition-colors"
          >
            <ArrowLeft size={16} />
            Return to Store
          </button>

          <div className="grid lg:grid-cols-5 gap-16">
            <div className="lg:col-span-3 space-y-12">
              <div className="space-y-8">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center text-[#137fec]">
                    <Truck size={20} />
                  </div>
                  <h2 className="text-2xl font-black text-slate-900">Shipping Information</h2>
                </div>

                <form id="checkout-form" onSubmit={handleProcessPayment} className="grid grid-cols-2 gap-6">
                  <div className="col-span-2">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Email Address</label>
                    <input required type="email" className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-[#137fec] outline-none" placeholder="alex@example.com" />
                  </div>
                  <div className="col-span-1">
                    <label className="block text-sm font-bold text-slate-700 mb-2">First Name</label>
                    <input required type="text" className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-[#137fec] outline-none" placeholder="Alex" />
                  </div>
                  <div className="col-span-1">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Last Name</label>
                    <input required type="text" className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-[#137fec] outline-none" placeholder="Smith" />
                  </div>
                  <div className="col-span-2">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Shipping Address</label>
                    <input required type="text" className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-[#137fec] outline-none" placeholder="123 Technology Way" />
                  </div>
                  <div className="col-span-1">
                    <label className="block text-sm font-bold text-slate-700 mb-2">City</label>
                    <input required type="text" className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-[#137fec] outline-none" placeholder="Lagos" />
                  </div>
                  <div className="col-span-1">
                    <label className="block text-sm font-bold text-slate-700 mb-2">ZIP Code</label>
                    <input required type="text" className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-[#137fec] outline-none" placeholder="100001" />
                  </div>
                </form>
              </div>

              <div className="space-y-8">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center text-[#137fec]">
                    <CreditCard size={20} />
                  </div>
                  <h2 className="text-2xl font-black text-slate-900">Payment Method</h2>
                </div>

                <div className="p-6 bg-slate-50 border border-slate-200 rounded-2xl flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-white rounded-xl shadow-sm">
                      <img src="https://assets.paystack.com/assets/img/logos/merchants/paystack-logo.png" alt="Paystack" className="h-4" />
                    </div>
                    <div>
                      <p className="font-bold text-slate-900">Pay with Paystack</p>
                      <p className="text-xs text-slate-500">Secure card and bank payments</p>
                    </div>
                  </div>
                  <div className="w-6 h-6 rounded-full border-4 border-[#137fec] bg-white"></div>
                </div>
              </div>
            </div>

            <div className="lg:col-span-2">
              <div className="bg-white border border-slate-100 rounded-3xl p-8 shadow-xl shadow-slate-200/50 sticky top-32 space-y-8">
                <h3 className="text-xl font-black text-slate-900">Order Summary</h3>

                <div className="space-y-6 max-h-[300px] overflow-y-auto pr-2 scrollbar-hide">
                  {cartItems.map(item => (
                    <div key={item.id} className="flex gap-4">
                      <img src={item.image} className="w-16 h-16 rounded-xl object-cover shrink-0" />
                      <div className="flex-1">
                        <p className="font-bold text-slate-900 text-sm line-clamp-1">{item.name}</p>
                        <p className="text-xs text-slate-400">Qty: {item.quantity}</p>
                      </div>
                      <span className="font-bold text-slate-900 text-sm">${(item.price * item.quantity).toFixed(2)}</span>
                    </div>
                  ))}
                </div>

                <div className="pt-6 border-t border-slate-100 space-y-3">
                  <div className="flex justify-between text-slate-500 text-sm">
                    <span>Subtotal</span>
                    <span className="font-bold text-slate-900">${calculateTotals().subtotal.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-slate-500 text-sm">
                    <span>VAT (7.5%)</span>
                    <span className="font-bold text-slate-900">${calculateTotals().vat.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-slate-500 text-sm">
                    <span>Shipping</span>
                    <span className="font-bold text-[#137fec]">Free</span>
                  </div>
                  <div className="pt-4 flex justify-between text-2xl font-black text-slate-900">
                    <span>Total</span>
                    <span>${calculateTotals().total.toFixed(2)}</span>
                  </div>
                </div>

                <button 
                  form="checkout-form"
                  disabled={isProcessing}
                  className="w-full py-4 bg-[#137fec] text-white font-black rounded-2xl shadow-xl shadow-blue-500/30 hover:bg-blue-600 transition-all flex items-center justify-center gap-3 disabled:opacity-70"
                >
                  {isProcessing ? (
                    <>
                      <Loader2 className="animate-spin" />
                      Processing...
                    </>
                  ) : (
                    <>
                      Complete Purchase
                      <ShieldCheck size={20} />
                    </>
                  )}
                </button>

                <p className="text-[10px] text-center text-slate-400 font-medium px-4">
                  By completing your purchase, you agree to our Terms of Service and Privacy Policy.
                </p>
              </div>
            </div>
          </div>
        </div>
      )}

      {view === View.CONFIRMATION && (
        <div className="max-w-3xl mx-auto px-4 py-32 text-center">
          <div className="flex justify-center mb-10">
            <div className="w-24 h-24 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-500 relative">
               <div className="absolute inset-0 rounded-full border-4 border-emerald-100 animate-ping"></div>
               <CheckCircle2 size={60} strokeWidth={1.5} />
            </div>
          </div>

          <h2 className="text-4xl font-black text-slate-900 tracking-tight mb-4">Payment Successful!</h2>
          <p className="text-lg text-slate-500 max-w-md mx-auto mb-12">
            Thank you for your purchase. We've sent a confirmation email to your inbox.
