          <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-lg mb-12 max-w-sm mx-auto">
             <div className="flex justify-between text-sm text-slate-400 mb-2 uppercase tracking-widest font-bold">
               <span>Order Ref</span>
               <span>Date</span>
