                <div className="inline-flex items-center gap-2 text-emerald-500 font-bold bg-emerald-50 px-4 py-1.5 rounded-full">
                   <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                   Processed
                </div>
             </div>
          </div>

          <button 
            onClick={() => setView(View.HOME)}
            className="px-12 py-4 bg-[#137fec] text-white font-black rounded-2xl shadow-xl shadow-blue-500/30 hover:bg-blue-600 transition-all"
          >
            Continue Shopping
          </button>
        </div>
      )}

      <Cart 
        isOpen={isCartOpen} 
