import { MOCK_PRODUCTS, VAT_RATE } from './constants';
import { ChevronRight, CheckCircle2, ShieldCheck, Truck, CreditCard, ArrowLeft, Loader2, SlidersHorizontal } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<View>(View.HOME);
  const [activeCategory, setActiveCategory] = useState<Category>('All');
  const [sortBy, setSortBy] = useState<SortOption>('recommended');
  const [searchQuery, setSearchQuery] = useState('');
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [wishlistIds, setWishlistIds] = useState<string[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isWishlistOpen, setIsWishlistOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [lastRef, setLastRef] = useState('');
  const [selectedProductId, setSelectedProductId] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const savedCart = localStorage.getItem('techstore_cart');
    const savedWishlist = localStorage.getItem('techstore_wishlist');
    if (savedCart) setCartItems(JSON.parse(savedCart));
    if (savedWishlist) setWishlistIds(JSON.parse(savedWishlist));
  }, []);

  useEffect(() => {
    localStorage.setItem('techstore_cart', JSON.stringify(cartItems));
  }, [cartItems]);

  useEffect(() => {
    localStorage.setItem('techstore_wishlist', JSON.stringify(wishlistIds));
  }, [wishlistIds]);

  const cartCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);
  const wishlistItems = useMemo(() => 
    MOCK_PRODUCTS.filter(p => wishlistIds.includes(p.id)), 
    [wishlistIds]
  );

  const filteredAndSortedProducts = useMemo(() => {
    let result = [...MOCK_PRODUCTS];

    // Filter by Category
    if (activeCategory !== 'All') {
      result = result.filter(p => p.category === activeCategory);
    }

    // Filter by Search Query
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.name.toLowerCase().includes(q) || 
        p.description.toLowerCase().includes(q) ||
        p.category.toLowerCase().includes(q)
      );
    }

    // Sort
    switch (sortBy) {
      case 'price_asc':
        result.sort((a, b) => a.price - b.price);
        break;
      case 'price_desc':
        result.sort((a, b) => b.price - a.price);
        break;
      case 'rating':
        result.sort((a, b) => b.rating - a.rating);
        break;
      default:
        // 'recommended' - use default ordering or custom logic
        break;
    }

    return result;
