  onOpenWishlist: () => void;
  onNavigateHome: () => void;
  onNavigateTrack: () => void;
  activeCategory: string;
  setActiveCategory: (cat: any) => void;
  searchQuery: string;
  setSearchQuery: (q: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ 
